import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequiredArgsConstructor
@RequestMapping("/categories")
public class CategoryController {
    private final CategoryService categoryService;

    @GetMapping
    public ApiResponse<List<CategoryResponse>> getAllCategories() {
        return ApiResponse.<List<CategoryResponse>>builder()
                .success(true)
                .code(200)
                .message("Lấy danh sách danh mục thành công")
                .data(categoryService.getAllCategories())
                .timestamp(LocalDateTime.now())
                .build();
    }

    @PostMapping
    @PreAuthorize("hasRole('ADMIN')")
    public ApiResponse<CategoryResponse> createCategory(@RequestBody @Valid CreateCategoryRequest request) {
        return ApiResponse.<CategoryResponse>builder()
                .success(true)
                .code(201)
                .message("Tạo danh mục thành công")
                .data(categoryService.createCategory(request))
                .timestamp(LocalDateTime.now())
                .build();
    }

    @PutMapping("/{id}")
    @PreAuthorize("hasRole('ADMIN')")
    public ApiResponse<CategoryResponse> updateCategory(
            @PathVariable Long id, @RequestBody @Valid UpdateCategoryRequest request) {
        return ApiResponse.<CategoryResponse>builder()
                .success(true)
                .code(200)
                .message("Cập nhật danh mục thành công")
                .data(categoryService.updateCategory(id, request))
                .timestamp(LocalDateTime.now())
                .build();
    }

    @DeleteMapping("/{id}")
    @PreAuthorize("hasRole('ADMIN')")
    public ApiResponse<Void> deleteCategory(@PathVariable Long id) {
        categoryService.deleteCategory(id);
        return ApiResponse.<Void>builder()
                .success(true)
                .code(200)
                .message("Xóa danh mục thành công")
                .timestamp(LocalDateTime.now())
                .build();
    }
}

package com.duybao.SplitGo.DTO.request;

import jakarta.validation.constraints.Email;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Pattern;
import jakarta.validation.constraints.Size;

import com.fasterxml.jackson.annotation.JsonInclude;

import lombok.Data;

@Data
@JsonInclude(JsonInclude.Include.NON_NULL)
public class UpdateUserRequest {
    @NotBlank(message = "NAME_NOT_NULL")
    @Size(max = 30, message = "NAME_TOO_LONG")
    private String fullName;

    @Email(message = "EMAIL_INVALID")
    @NotBlank(message = "EMAIL_NOT_NULL")
    private String email;

    @Pattern(regexp = "^(0)([35789])\\d{8}$", message = "PHONE_INVALID")
    private String phone;

    @Size(max = 60, message = "ADDRESS_TOO_LONG")
    private String address;
}

